import React, { useState, useEffect } from 'react';
import api from '../services/authService';

interface WeightRecord {
  id: number;
  animal_id: number;
  animal_identificador: string;
  peso: number;
  fecha: string;
  edad_dias: number;
  ganancia_diaria?: number;
  observaciones?: string;
}

interface GrowthStats {
  totalPesajes: number;
  pesoPromedio: number;
  gananciaPromedio: number;
  animalesListos: number;
}

const Weights: React.FC = () => {
  const [weights, setWeights] = useState<WeightRecord[]>([]);
  const [stats, setStats] = useState<GrowthStats>({
    totalPesajes: 0,
    pesoPromedio: 0,
    gananciaPromedio: 0,
    animalesListos: 0
  });
  const [loading, setLoading] = useState(true);
  const [showForm, setShowForm] = useState(false);
  const [selectedAnimal, setSelectedAnimal] = useState<number | null>(null);
  const [formData, setFormData] = useState({
    animal_id: '',
    peso: '',
    fecha: new Date().toISOString().split('T')[0],
    observaciones: ''
  });

  useEffect(() => {
    loadWeights();
  }, []);

  const loadWeights = async () => {
    try {
      const response = await api.get('/weights');
      const weightsData = response.data || [];
      setWeights(weightsData);

      // Calcular estadísticas
      const totalPesajes = weightsData.length;
      const pesoPromedio = weightsData.length > 0 
        ? weightsData.reduce((acc: number, w: WeightRecord) => acc + w.peso, 0) / weightsData.length 
        : 0;
      const gananciaPromedio = weightsData.length > 0
        ? weightsData.reduce((acc: number, w: WeightRecord) => acc + (w.ganancia_diaria || 0), 0) / weightsData.length
        : 0;
      const animalesListos = weightsData.filter((w: WeightRecord) => w.peso >= 100).length;

      setStats({
        totalPesajes,
        pesoPromedio: Math.round(pesoPromedio * 10) / 10,
        gananciaPromedio: Math.round(gananciaPromedio * 10) / 10,
        animalesListos
      });
    } catch (error) {
      console.error('Error cargando pesajes:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await api.post('/weights', formData);
      alert('Pesaje registrado exitosamente');
      setFormData({
        animal_id: '',
        peso: '',
        fecha: new Date().toISOString().split('T')[0],
        observaciones: ''
      });
      setShowForm(false);
      loadWeights();
    } catch (error) {
      console.error('Error guardando pesaje:', error);
      alert('Error guardando pesaje');
    }
  };

  const calculateProjectedWeight = (currentWeight: number, dailyGain: number, targetWeight: number) => {
    if (dailyGain <= 0) return 0;
    const remainingWeight = targetWeight - currentWeight;
    return Math.ceil(remainingWeight / (dailyGain / 1000)); // dailyGain en gramos
  };

  const getWeightStatus = (peso: number) => {
    if (peso >= 100) return { color: '#31ce36', status: 'Listo para venta' };
    if (peso >= 70) return { color: '#ffad46', status: 'Próximo a venta' };
    if (peso >= 30) return { color: '#1572e8', status: 'En crecimiento' };
    return { color: '#6c757d', status: 'Lechón' };
  };

  if (loading) {
    return (
      <div className="page-inner">
        <div className="card">
          <div style={{ padding: '40px', textAlign: 'center' }}>
            <i className="fas fa-spinner fa-spin" style={{ fontSize: '24px', color: '#1572e8' }}></i>
            <p style={{ marginTop: '10px', color: '#6c757d' }}>Cargando datos de pesajes...</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="page-inner">
      <div className="card">
        <div className="card-header">
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <h4 className="card-title">
              <i className="fas fa-weight" style={{ marginRight: '10px' }}></i>
              Control de Peso y Crecimiento
            </h4>
            <button className="btn btn-primary" onClick={() => setShowForm(!showForm)}>
              <i className={`fas ${showForm ? 'fa-times' : 'fa-plus'}`} style={{ marginRight: '8px' }}></i>
              {showForm ? 'Cancelar' : 'Nuevo Pesaje'}
            </button>
          </div>
        </div>

        <div style={{ padding: '25px' }}>
          {/* Formulario */}
          {showForm && (
            <div className="card" style={{ marginBottom: '25px' }}>
              <div className="card-header">
                <h5 className="card-title">
                  <i className="fas fa-plus" style={{ marginRight: '8px' }}></i>
                  Registrar Pesaje
                </h5>
              </div>
              <div style={{ padding: '20px' }}>
                <form onSubmit={handleSubmit}>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '15px', marginBottom: '15px' }}>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Animal *</label>
                      <select
                        value={formData.animal_id}
                        onChange={(e) => setFormData({...formData, animal_id: e.target.value})}
                        required
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                      >
                        <option value="">Seleccionar animal</option>
                        <option value="1">CER001 - Cerda Principal</option>
                        <option value="2">LEC001 - Lechón Joven</option>
                        <option value="3">ENG001 - Cerdo Engorde</option>
                        <option value="4">VER001 - Verraco Alpha</option>
                      </select>
                    </div>
                    <div>
                      <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Fecha *</label>
                      <input
                        type="date"
                        value={formData.fecha}
                        onChange={(e) => setFormData({...formData, fecha: e.target.value})}
                        required
                        style={{
                          width: '100%',
                          padding: '10px',
                          border: '1px solid #ebedf2',
                          borderRadius: '8px',
                          fontSize: '14px'
                        }}
                      />
                    </div>
                  </div>

                  <div style={{ marginBottom: '15px' }}>
                    <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Peso (kg) *</label>
                    <input
                      type="number"
                      step="0.1"
                      value={formData.peso}
                      onChange={(e) => setFormData({...formData, peso: e.target.value})}
                      required
                      style={{
                        width: '100%',
                        padding: '10px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px'
                      }}
                      placeholder="Ej: 45.5"
                    />
                  </div>

                  <div style={{ marginBottom: '20px' }}>
                    <label style={{ display: 'block', marginBottom: '5px', fontWeight: '600', color: '#1a2035' }}>Observaciones</label>
                    <textarea
                      value={formData.observaciones}
                      onChange={(e) => setFormData({...formData, observaciones: e.target.value})}
                      rows={3}
                      style={{
                        width: '100%',
                        padding: '10px',
                        border: '1px solid #ebedf2',
                        borderRadius: '8px',
                        fontSize: '14px',
                        resize: 'vertical'
                      }}
                      placeholder="Observaciones del pesaje..."
                    />
                  </div>

                  <div style={{ display: 'flex', gap: '10px' }}>
                    <button type="submit" className="btn btn-success">
                      <i className="fas fa-save" style={{ marginRight: '8px' }}></i>
                      Guardar
                    </button>
                    <button type="button" className="btn btn-secondary" onClick={() => setShowForm(false)}>
                      Cancelar
                    </button>
                  </div>
                </form>
              </div>
            </div>
          )}

          {/* Stats */}
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px', marginBottom: '25px' }}>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#1572e8' }}>{stats.totalPesajes}</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>PESAJES REGISTRADOS</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#31ce36' }}>{stats.pesoPromedio}kg</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>PESO PROMEDIO</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#ffad46' }}>{stats.gananciaPromedio}g</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>GANANCIA DIARIA</div>
            </div>
            <div style={{ background: '#f8f9fa', padding: '20px', borderRadius: '8px', textAlign: 'center' }}>
              <div style={{ fontSize: '28px', fontWeight: '700', color: '#f25961' }}>{stats.animalesListos}</div>
              <div style={{ fontSize: '14px', color: '#6c757d', fontWeight: '600' }}>LISTOS PARA VENTA</div>
            </div>
          </div>

          {/* Alertas de Animales Listos */}
          {stats.animalesListos > 0 && (
            <div style={{ marginBottom: '25px', padding: '15px', background: '#d4edda', borderRadius: '8px', border: '1px solid #c3e6cb' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                <i className="fas fa-check-circle" style={{ fontSize: '24px', color: '#31ce36' }}></i>
                <div>
                  <div style={{ fontWeight: '600', color: '#1a2035' }}>Animales Listos para Venta</div>
                  <div style={{ fontSize: '14px', color: '#6c757d' }}>
                    {stats.animalesListos} animales han alcanzado el peso objetivo (≥100kg) y están listos para venta
                  </div>
                </div>
              </div>
            </div>
          )}

          {/* Tabla de Pesajes */}
          <div className="table-responsive">
            <table className="table">
              <thead>
                <tr>
                  <th>Animal</th>
                  <th>Peso (kg)</th>
                  <th>Fecha</th>
                  <th>Edad (días)</th>
                  <th>Ganancia Diaria</th>
                  <th>Estado</th>
                  <th>Proyección</th>
                  <th>Acciones</th>
                </tr>
              </thead>
              <tbody>
                {weights.map(weight => {
                  const status = getWeightStatus(weight.peso);
                  const daysToMarket = weight.ganancia_diaria 
                    ? calculateProjectedWeight(weight.peso, weight.ganancia_diaria, 100)
                    : 0;

                  return (
                    <tr key={weight.id}>
                      <td style={{ fontWeight: '600' }}>{weight.animal_identificador}</td>
                      <td>
                        <span style={{ fontSize: '16px', fontWeight: '700', color: status.color }}>
                          {weight.peso}kg
                        </span>
                      </td>
                      <td>{new Date(weight.fecha).toLocaleDateString()}</td>
                      <td>{weight.edad_dias} días</td>
                      <td>
                        {weight.ganancia_diaria ? (
                          <span style={{ 
                            color: weight.ganancia_diaria >= 500 ? '#31ce36' : 
                                   weight.ganancia_diaria >= 400 ? '#ffad46' : '#f25961',
                            fontWeight: '600'
                          }}>
                            {weight.ganancia_diaria}g/día
                          </span>
                        ) : '-'}
                      </td>
                      <td>
                        <span style={{
                          padding: '4px 8px',
                          borderRadius: '12px',
                          fontSize: '12px',
                          fontWeight: '600',
                          background: status.color,
                          color: '#ffffff'
                        }}>
                          {status.status}
                        </span>
                      </td>
                      <td>
                        {weight.peso < 100 && daysToMarket > 0 ? (
                          <span style={{ fontSize: '12px', color: '#6c757d' }}>
                            {daysToMarket} días a 100kg
                          </span>
                        ) : weight.peso >= 100 ? (
                          <span style={{ fontSize: '12px', color: '#31ce36', fontWeight: '600' }}>
                            ✓ Peso objetivo
                          </span>
                        ) : '-'}
                      </td>
                      <td>
                        <div style={{ display: 'flex', gap: '5px' }}>
                          <button 
                            className="btn btn-primary btn-sm" 
                            title="Ver historial"
                            onClick={() => setSelectedAnimal(weight.animal_id)}
                          >
                            <i className="fas fa-chart-line"></i>
                          </button>
                          <button className="btn btn-warning btn-sm" title="Editar">
                            <i className="fas fa-edit"></i>
                          </button>
                          <button className="btn btn-success btn-sm" title="Nuevo pesaje">
                            <i className="fas fa-plus"></i>
                          </button>
                        </div>
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>

          {weights.length === 0 && (
            <div style={{ textAlign: 'center', padding: '40px', color: '#6c757d' }}>
              <i className="fas fa-weight" style={{ fontSize: '48px', marginBottom: '15px', opacity: 0.5 }}></i>
              <h5>No hay pesajes registrados</h5>
              <p>Comienza registrando el primer pesaje</p>
              <button className="btn btn-primary" onClick={() => setShowForm(true)}>
                <i className="fas fa-plus" style={{ marginRight: '8px' }}></i>
                Registrar Pesaje
              </button>
            </div>
          )}

          {/* Modal de Historial (placeholder) */}
          {selectedAnimal && (
            <div style={{
              position: 'fixed',
              top: 0,
              left: 0,
              right: 0,
              bottom: 0,
              background: 'rgba(0,0,0,0.5)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              zIndex: 9999
            }}>
              <div className="card" style={{ width: '600px', maxHeight: '80vh', overflow: 'auto' }}>
                <div className="card-header">
                  <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                    <h5 className="card-title">
                      <i className="fas fa-chart-line" style={{ marginRight: '8px' }}></i>
                      Historial de Crecimiento
                    </h5>
                    <button 
                      className="btn btn-secondary btn-sm"
                      onClick={() => setSelectedAnimal(null)}
                    >
                      <i className="fas fa-times"></i>
                    </button>
                  </div>
                </div>
                <div style={{ padding: '20px', textAlign: 'center' }}>
                  <i className="fas fa-chart-area" style={{ fontSize: '48px', color: '#6c757d', marginBottom: '15px', opacity: 0.5 }}></i>
                  <h5 style={{ color: '#1a2035' }}>Curva de Crecimiento</h5>
                  <p style={{ color: '#6c757d' }}>
                    Aquí se mostraría el gráfico de evolución del peso del animal seleccionado
                  </p>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Weights;
